  1	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
  2	import {
  3	  Accordion,
  4	  AccordionContent,
  5	  AccordionExpandableContentBody,
  6	  AccordionItem,
  7	  AccordionToggle,
  8	  Text,
  9	  TextContent,
 10	  TextVariants
 11	} from '@patternfly/react-core';
 12	import _ from 'lodash';
 13	import * as React from 'react';
 14	import { useTranslation } from 'react-i18next';
 15	import { Record } from '../../api/ipfix';
 16	import { NetflowMetrics, Stats } from '../../api/loki';
 17	import { RecordType } from '../../model/flow-query';
 18	import { Warning } from '../../model/warnings';
 19	import { compareStrings } from '../../utils/base-compare';
 20	import { config } from '../../utils/config';
 21	import { TimeRange } from '../../utils/datetime';
 22	import { formatDuration, formatDurationAboveMillisecond, formatDurationAboveNanosecond } from '../../utils/duration';
 23	import { compareIPs } from '../../utils/ip';
 24	import { comparePorts, formatPort } from '../../utils/port';
 25	import { formatProtocol } from '../../utils/protocol';
 26	import { FlowsQuerySummaryContent } from './flows-query-summary-content';
 27	import { MetricsQuerySummaryContent } from './metrics-query-summary-content';
 28	
 29	type TypeCardinality = {
 30	  type: string;
 31	  objects: K8SObjectCardinality[];
 32	};
 33	
 34	type K8SObjectCardinality = {
 35	  namespace?: string;
 36	  names: string[];
 37	};
 38	
 39	export interface SummaryPanelContentProps {
 40	  flows?: Record[];
 41	  metrics: NetflowMetrics;
 42	  type: RecordType;
 43	  stats?: Stats;
 44	  maxChunkAge?: number;
 45	  limit: number;
 46	  range: number | TimeRange;
 47	  lastRefresh?: Date;
 48	  lastDuration?: number;
 49	  warning?: Warning;
 50	  showDNSLatency?: boolean;
 51	  showRTTLatency?: boolean;
 52	}
 53	
 54	export const SummaryPanelContent: React.FC<SummaryPanelContentProps> = ({
 55	  flows,
 56	  metrics,
 57	  type,
 58	  stats,
 59	  maxChunkAge,
 60	  limit,
 61	  range,
 62	  lastRefresh,
 63	  lastDuration,
 64	  warning,
 65	  showDNSLatency,
 66	  showRTTLatency
 67	}) => {
 68	  const { t } = useTranslation('plugin__netobserv-plugin');
 69	  const [expanded, setExpanded] = React.useState<string>('');
 70	
 71	  const accordionItem = (id: string, label: string, content: JSX.Element) => {
 72	    return (
 73	      <AccordionItem key={id}>
 74	        <AccordionToggle
 75	          onClick={() => {
 76	            if (id === expanded) {
 77	              setExpanded('');
 78	            } else {
 79	              setExpanded(id);
 80	            }
 81	          }}
 82	          id={id}
 83	
 84	        >
 85	          {label}
 86	        </AccordionToggle>
 87	        <AccordionContent id={`${id}-content`} isCustomContent>
 88	          {content}
 89	        </AccordionContent>
 90	      </AccordionItem>
 91	    );
 92	  };
 93	
 94	  const typeCardinalityContent = (tc: TypeCardinality) => {
 95	    return (
 96	      <>
 97	        {tc.objects
 98	          .sort((a, b) => compareStrings(a.namespace ? a.namespace : '', b.namespace ? b.namespace : ''))
 99	          .flatMap(o => (
100	            <AccordionExpandableContentBody key={`${tc.type}-${o.namespace}`}>
101	              {o.namespace && <ResourceLink kind={'Namespace'} name={o.namespace} />}
102	              {o.names
103	                .sort((a, b) => compareStrings(a, b))
104	                .map(n => (
105	                  <div
106	                    key={`${tc.type}-${n}-${o.namespace}`}
107	                    className={o.namespace ? 'summary-container-grouped' : ''}
108	                  >
109	                    <ResourceLink kind={tc.type} name={n} namespace={o.namespace} />
110	                  </div>
111	                ))}
112	            </AccordionExpandableContentBody>
113	          ))}
114	      </>
115	    );
116	  };
117	
118	  const listCardinalityContent = (
119	    values: (string | number)[],
120	    compareFn?: (a: string | number, b: string | number) => number
121	  ) => {
122	    const sortedStrings = compareFn
123	      ? (values.sort((a: string | number, b: string | number) => compareFn(a, b)) as string[])
124	      : values;
125	    return (
126	      <>
127	        {sortedStrings.map((v: string) => (
128	          <AccordionExpandableContentBody key={v}>
129	            <Text component="p">{v}</Text>
130	          </AccordionExpandableContentBody>
131	        ))}
132	      </>
133	    );
134	  };
135	
136	  const configContent = () => {
137	    return (
138	      <TextContent className="summary-text-container">
139	        <Text component={TextVariants.h3}>{`${t('Configuration')}`}</Text>
140	        <Text component="p" className="summary-config-item">{`${t('Sampling')}: ${config.sampling}`}</Text>
141	        {maxChunkAge && (
142	          <Text component="p" className="summary-config-item">{`${t('Max chunk age')}: ${formatDuration(
143	            maxChunkAge
144	          )}`}</Text>
145	        )}
146	      </TextContent>
147	    );
148	  };
149	
150	  const versionContent = () => {
151	    return (
152	      <TextContent className="summary-text-container">
153	        <Text component={TextVariants.h3}>{`${t('Version')}`}</Text>
154	        <Text component="p" className="summary-config-item">{`${t('Number')}: ${config.buildVersion}`}</Text>
155	        <Text component="p" className="summary-config-item">{`${t('Date')}: ${config.buildDate}`}</Text>
156	      </TextContent>
157	    );
158	  };
159	
160	  const cardinalityContent = () => {
161	    const rateMetrics = metrics.rate.map(r => r.bytes || r.packets).or([]);
162	
163	    //regroup all k8s objects per type + namespace
164	    const namespaces: string[] = [];
165	    const typesCardinality: TypeCardinality[] = [];
166	    let addresses: string[] = [];
167	    let ports: number[] = [];
168	    let protocols: number[] = [];
169	
170	    if (flows && flows.length) {
171	      //list all types
172	      const types = Array.from(new Set(flows.flatMap(f => [f.labels.SrcK8S_Type, f.labels.DstK8S_Type])));
173	      types
174	        .filter((t: string | undefined) => t !== undefined)
175	        .forEach((type: string) => {
176	          const tc: TypeCardinality = { type, objects: [] };
177	
178	          const typeFilteredFlows = flows.filter(f => [f.labels.SrcK8S_Type, f.labels.DstK8S_Type].includes(type));
179	          //list all namespaces of this type
180	          const typeNamespaces = new Set(
181	            typeFilteredFlows.flatMap(f => [f.labels.SrcK8S_Namespace, f.labels.DstK8S_Namespace])
182	          );
183	          typeNamespaces.forEach(namespace => {
184	            const namespaceFilteredFlows = typeFilteredFlows.filter(f =>
185	              [f.labels.SrcK8S_Namespace, f.labels.DstK8S_Namespace].includes(namespace)
186	            );
187	
188	            const nsObject: K8SObjectCardinality = {
189	              namespace,
190	              names: []
191	            };
192	
193	            //add all names of this namespace of type
194	            namespaceFilteredFlows.forEach(record => {
195	              const srcName =
196	                record.labels.SrcK8S_Type === type && record.labels.SrcK8S_Namespace === namespace
197	                  ? record.fields.SrcK8S_Name
198	                  : undefined;
199	              if (srcName && !nsObject.names.includes(srcName)) {
200	                nsObject.names.push(srcName);
201	              }
202	              const dstName =
203	                record.labels.DstK8S_Type === type && record.labels.DstK8S_Namespace === namespace
204	                  ? record.fields.DstK8S_Name
205	                  : undefined;
206	              if (dstName && !nsObject.names.includes(dstName)) {
207	                nsObject.names.push(dstName);
208	              }
209	            });
210	
211	            if (!_.isEmpty(nsObject.names)) {
212	              tc.objects.push(nsObject);
213	            }
214	
215	            if (namespace && !namespaces.includes(namespace)) {
216	              namespaces.push(namespace);
217	            }
218	          });
219	          typesCardinality.push(tc);
220	        });
221	
222	      addresses = Array.from(
223	        new Set(flows.map(f => f.fields.SrcAddr || '').concat(flows.map(f => f.fields.DstAddr || '')))
224	      );
225	      ports = Array.from(
226	        new Set(
227	          flows
228	            .filter(f => f.fields.SrcPort)
229	            .map(f => f.fields.SrcPort)
230	            .concat(flows.filter(f => f.fields.DstPort).map(f => f.fields.DstPort)) as number[]
231	        )
232	      );
233	      protocols = Array.from(new Set(flows.map(f => f.fields.Proto || NaN)));
234	    } else if (rateMetrics) {
235	      function manageTypeCardinality(hostName?: string, namespace?: string, type?: string, name?: string) {
236	        if (namespace && !namespaces.includes(namespace)) {
237	          namespaces.push(namespace);
238	        }
239	
240	        if (type) {
241	          let tc = typesCardinality.find(t => t.type === type);
242	          if (!tc) {
243	            tc = { type: type, objects: [] };
244	            typesCardinality.push(tc);
245	          }
246	
247	          let object = tc.objects.find(o => o.namespace === namespace);
248	          if (!object) {
249	            object = { names: [], namespace: namespace };
250	            tc.objects.push(object);
251	          }
252	
253	          if (name && !object.names.includes(name)) {
254	            object.names.push(name);
255	          }
256	        }
257	
258	        if (hostName) {
259	          manageTypeCardinality('', '', 'Node', hostName);
260	        }
261	      }
262	
263	      rateMetrics.forEach(m => {
264	        manageTypeCardinality(m.source.host, m.source.namespace, m.source.resource?.type, m.source.resource?.name);
265	        manageTypeCardinality(
266	          m.destination.host,
267	          m.destination.namespace,
268	          m.destination.resource?.type,
269	          m.destination.resource?.name
270	        );
271	      });
272	
273	      addresses = Array.from(
274	        new Set(rateMetrics.map(m => m.source.addr).concat(rateMetrics.map(m => m.destination.addr)))
275	      ).filter(v => !_.isEmpty(v)) as string[];
276	    }
277	
278	    if (!_.isEmpty(namespaces)) {
279	      typesCardinality.push({
280	        type: 'Namespace',
281	        objects: [{ names: namespaces }]
282	      });
283	    }
284	
285	    return addresses.length || typesCardinality.length || ports.length || protocols.length ? (
286	      <TextContent className="summary-text-container">
287	        <Text component={TextVariants.h3}>{`${t('Cardinality')} ${
288	          !_.isEmpty(rateMetrics) ? t('(top {{limit}} metrics)', { limit }) : ''
289	        }`}</Text>
290	        <Accordion id="cardinality-accordion">
291	          {addresses.length
292	            ? accordionItem(
293	                'addresses',
294	                t('{{n}} IP(s)', { n: addresses.length }),
295	                listCardinalityContent(addresses, compareIPs)
296	              )
297	            : undefined}
298	          {typesCardinality.length
299	            ? typesCardinality.map(tc =>
300	                accordionItem(
301	                  tc.type,
302	                  `${tc.objects.map(o => o.names.length).reduce((a, b) => a + b, 0)} ${tc.type}(s)`,
303	                  typeCardinalityContent(tc)
304	                )
305	              )
306	            : undefined}
307	          {ports.length
308	            ? accordionItem(
309	                'ports',
310	                t('{{n}} Port(s)', { n: ports.length }),
311	                listCardinalityContent(
312	                  //sort ports before format to keep number order
313	                  ports.sort((p1, p2) => comparePorts(p1, p2)).map(p => formatPort(p))
314	                )
315	              )
316	            : undefined}
317	          {protocols.length
318	            ? accordionItem(
319	                'protocols',
320	                t('{{n}} Protocol(s)', { n: protocols.length }),
321	                listCardinalityContent(
322	                  protocols.map(p => formatProtocol(p, t)),
323	                  compareStrings
324	                )
325	              )
326	            : undefined}
327	        </Accordion>
328	      </TextContent>
329	    ) : undefined;
330	  };
331	
332	  const dnsLatency = (filteredFlows: Record[]) => {
333	    const filteredDNSFlows = filteredFlows.filter(f => f.fields.DnsLatencyMs !== undefined);
334	
335	    const dnsLatency = filteredDNSFlows.length
336	      ? filteredDNSFlows.map(f => f.fields.DnsLatencyMs!).reduce((a, b) => a + b, 0) / filteredDNSFlows.length
337	      : NaN;
338	
339	    return (
340	      <Text component="p" className="summary-config-item">{`${t('DNS latency')}: ${
341	        isNaN(dnsLatency) ? t('n/a') : formatDurationAboveMillisecond(dnsLatency)
342	      }`}</Text>
343	    );
344	  };
345	
346	  const rttLatency = (filteredFlows: Record[]) => {
347	    const filteredRTTFlows = filteredFlows.filter(f => f.fields.TimeFlowRttNs !== undefined);
348	
349	    const rtt = filteredRTTFlows.length
350	      ? filteredRTTFlows.map(f => f.fields.TimeFlowRttNs!).reduce((a, b) => a + b, 0) / filteredRTTFlows.length
351	      : NaN;
352	
353	    return (
354	      <Text component="p" className="summary-config-item">{`${t('Flow RTT')}: ${
355	        isNaN(rtt) ? t('n/a') : formatDurationAboveNanosecond(rtt)
356	      }`}</Text>
357	    );
358	  };
359	
360	  const timeContent = () => {
361	    const filteredFlows = flows || [];
362	    const duration = filteredFlows.length
363	      ? filteredFlows
364	          .map(f => (f.fields.TimeFlowEndMs || 0) - (f.fields.TimeFlowStartMs || 0))
365	          .reduce((a, b) => a + b, 0) / filteredFlows.length
366	      : 0;
367	    const collectionLatency = filteredFlows.length
368	      ? filteredFlows
369	          .map(f => (f.fields.TimeReceived || 0) * 1000 - (f.fields.TimeFlowEndMs || 0))
370	          .reduce((a, b) => a + b, 0) / filteredFlows.length
371	      : 0;
372	
373	    return flows && flows.length ? (
374	      <TextContent className="summary-text-container">
375	        <Text component={TextVariants.h3}>{`${t('Average time')}`}</Text>
376	        <Text component="p" className="summary-config-item">{`${t('Duration')}: ${formatDurationAboveMillisecond(
377	          duration
378	        )}`}</Text>
379	        {showRTTLatency ? rttLatency(filteredFlows) : <></>}
380	        <Text component="p" className="summary-config-item">{`${t(
381	          'Collection latency'
382	        )}: ${formatDurationAboveMillisecond(collectionLatency)}`}</Text>
383	        {showDNSLatency ? dnsLatency(filteredFlows) : <></>}
384	      </TextContent>
385	    ) : (
386	      <></>
387	    );
388	  };
389	
390	  return (
391	    <div className="scrollable-panel">
392	      <TextContent className="summary-text-container">
393	        {!_.isEmpty(flows) && stats?.limitReached && (
394	          <Text component={TextVariants.p}>
395	            {t(
396	              // eslint-disable-next-line max-len
397	              'Flow per request limit reached, following metrics can be inaccurate. Narrow down your search or increase limit.'
398	            )}
399	          </Text>
400	        )}
401	        <Text component={TextVariants.h3}>{`${t('Results')} ${
402	          _.isEmpty(flows) ? t('(top {{limit}} metrics)', { limit }) : ''
403	        }`}</Text>
404	        {_.isEmpty(flows) ? (
405	          <MetricsQuerySummaryContent
406	            className="summary-container-grouped"
407	            direction="column"
408	            metrics={metrics}
409	            numQueries={stats?.numQueries}
410	            dataSources={stats?.dataSources}
411	            lastRefresh={lastRefresh}
412	            lastDuration={lastDuration}
413	            warning={warning}
414	          />
415	        ) : (
416	          <FlowsQuerySummaryContent
417	            className="summary-container-grouped"
418	            direction="column"
419	            type={type}
420	            flows={flows!}
421	            numQueries={stats?.numQueries}
422	            limitReached={stats?.limitReached || false}
423	            range={range}
424	            lastRefresh={lastRefresh}
425	            lastDuration={lastDuration}
426	            warning={warning}
427	          />
428	        )}
429	      </TextContent>
430	
431	      {timeContent()}
432	
433	      {cardinalityContent()}
434	
435	      {configContent()}
436	
437	      {versionContent()}
438	    </div>
439	  );
440	};
441	
442	export default SummaryPanelContent;

