362	          .map(f => (f.fields.TimeFlowEndMs || 0) - (f.fields.TimeFlowStartMs || 0))
363	          .reduce((a, b) => a + b, 0) / filteredFlows.length
364	      : 0;
365	    const collectionLatency = filteredFlows.length
366	      ? filteredFlows
367	          .map(f => (f.fields.TimeReceived || 0) * 1000 - (f.fields.TimeFlowEndMs || 0))
368	          .reduce((a, b) => a + b, 0) / filteredFlows.length
369	      : 0;
370	
371	    return flows && flows.length ? (
372	      <Content className="summary-text-container">
373	        <Content component={ContentVariants.h3}>{`${t('Average time')}`}</Content>
374	        <Content component="p" className="summary-config-item">{`${t('Duration')}: ${formatDurationAboveMillisecond(
375	          duration
376	        )}`}</Content>
377	        {showRTTLatency ? rttLatency(filteredFlows) : <></>}
378	        <Content component="p" className="summary-config-item">{`${t(
379	          'Collection latency'
380	        )}: ${formatDurationAboveMillisecond(collectionLatency)}`}</Content>
381	        {showDNSLatency ? dnsLatency(filteredFlows) : <></>}
382	      </Content>
383	    ) : (
384	      <></>
385	    );
386	  };
387	
388	  return (
389	    <div className="scrollable-panel">
390	      <Content className="summary-text-container">
391	        {!_.isEmpty(flows) && stats?.limitReached && (
392	          <Content component={ContentVariants.p}>
393	            {t(
394	              // eslint-disable-next-line max-len
395	              'Flow per request limit reached, following metrics can be inaccurate. Narrow down your search or increase limit.'
396	            )}
397	          </Content>
398	        )}
399	        <Content component={ContentVariants.h3}>{`${t('Results')} ${
400	          _.isEmpty(flows) ? t('(top {{limit}} metrics)', { limit }) : ''
401	        }`}</Content>
402	        {_.isEmpty(flows) ? (
403	          <MetricsQuerySummaryContent
404	            className="summary-container-grouped"
405	            direction="column"
406	            metrics={metrics}
407	            numQueries={stats?.numQueries}
408	            dataSources={stats?.dataSources}
409	            lastRefresh={lastRefresh}
410	            lastDuration={lastDuration}
411	            warning={warning}
412	          />
413	        ) : (
414	          <FlowsQuerySummaryContent
415	            className="summary-container-grouped"
416	            direction="column"
417	            type={type}
418	            flows={flows!}
419	            numQueries={stats?.numQueries}
420	            limitReached={stats?.limitReached || false}
421	            range={range}
422	            lastRefresh={lastRefresh}
423	            lastDuration={lastDuration}
424	            warning={warning}
425	          />
426	        )}
427	      </Content>
428	
429	      {timeContent()}
430	
431	      {cardinalityContent()}
432	
433	      {configContent()}
434	
435	      {versionContent()}
436	    </div>
437	  );
