  1	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
  2	import {
  3	  Accordion,
  4	  AccordionContent,
  5	  AccordionExpandableContentBody,
  6	  AccordionItem,
  7	  AccordionToggle,
  8	  Content,
  9	  ContentVariants
 10	} from '@patternfly/react-core';
 11	import _ from 'lodash';
 12	import * as React from 'react';
 13	import { useTranslation } from 'react-i18next';
 14	import { Record } from '../../api/ipfix';
 15	import { NetflowMetrics, Stats } from '../../api/loki';
 16	import { RecordType } from '../../model/flow-query';
 17	import { Warning } from '../../model/warnings';
 18	import { compareStrings } from '../../utils/base-compare';
 19	import { config } from '../../utils/config';
 20	import { TimeRange } from '../../utils/datetime';
 21	import { formatDuration, formatDurationAboveMillisecond, formatDurationAboveNanosecond } from '../../utils/duration';
 22	import { compareIPs } from '../../utils/ip';
 23	import { comparePorts, formatPort } from '../../utils/port';
 24	import { formatProtocol } from '../../utils/protocol';
 25	import { FlowsQuerySummaryContent } from './flows-query-summary-content';
 26	import { MetricsQuerySummaryContent } from './metrics-query-summary-content';
 27	
 28	type TypeCardinality = {
 29	  type: string;
 30	  objects: K8SObjectCardinality[];
 31	};
 32	
 33	type K8SObjectCardinality = {
 34	  namespace?: string;
 35	  names: string[];
 36	};
 37	
 38	export interface SummaryPanelContentProps {
 39	  flows?: Record[];
 40	  metrics: NetflowMetrics;
 41	  type: RecordType;
 42	  stats?: Stats;
 43	  maxChunkAge?: number;
 44	  limit: number;
 45	  range: number | TimeRange;
 46	  lastRefresh?: Date;
 47	  lastDuration?: number;
 48	  warning?: Warning;
 49	  showDNSLatency?: boolean;
 50	  showRTTLatency?: boolean;
 51	}
 52	
 53	export const SummaryPanelContent: React.FC<SummaryPanelContentProps> = ({
 54	  flows,
 55	  metrics,
 56	  type,
 57	  stats,
 58	  maxChunkAge,
 59	  limit,
 60	  range,
 61	  lastRefresh,
 62	  lastDuration,
 63	  warning,
 64	  showDNSLatency,
 65	  showRTTLatency
 66	}) => {
 67	  const { t } = useTranslation('plugin__netobserv-plugin');
 68	  const [expanded, setExpanded] = React.useState<string>('');
 69	
 70	  const accordionItem = (id: string, label: string, content: JSX.Element) => {
 71	    return (
 72	      <AccordionItem key={id} isExpanded={expanded === id}>
 73	        <AccordionToggle
 74	          onClick={() => {
 75	            if (id === expanded) {
 76	              setExpanded('');
 77	            } else {
 78	              setExpanded(id);
 79	            }
 80	          }}
 81	          id={id}
 82	        >
 83	          {label}
 84	        </AccordionToggle>
 85	        <AccordionContent id={`${id}-content`} isCustomContent>
 86	          {content}
 87	        </AccordionContent>
 88	      </AccordionItem>
 89	    );
 90	  };
 91	
 92	  const typeCardinalityContent = (tc: TypeCardinality) => {
 93	    return (
 94	      <>
 95	        {tc.objects
 96	          .sort((a, b) => compareStrings(a.namespace ? a.namespace : '', b.namespace ? b.namespace : ''))
 97	          .flatMap(o => (
 98	            <AccordionExpandableContentBody key={`${tc.type}-${o.namespace}`}>
 99	              {o.namespace && <ResourceLink kind={'Namespace'} name={o.namespace} />}
100	              {o.names
101	                .sort((a, b) => compareStrings(a, b))
102	                .map(n => (
103	                  <div
104	                    key={`${tc.type}-${n}-${o.namespace}`}
105	                    className={o.namespace ? 'summary-container-grouped' : ''}
106	                  >
107	                    <ResourceLink kind={tc.type} name={n} namespace={o.namespace} />
108	                  </div>
109	                ))}
110	            </AccordionExpandableContentBody>
111	          ))}
112	      </>
113	    );
114	  };
115	
116	  const listCardinalityContent = (
117	    values: (string | number)[],
118	    compareFn?: (a: string | number, b: string | number) => number
119	  ) => {
120	    const sortedStrings = compareFn
121	      ? (values.sort((a: string | number, b: string | number) => compareFn(a, b)) as string[])
122	      : values;
123	    return (
124	      <>
125	        {sortedStrings.map((v: string) => (
126	          <AccordionExpandableContentBody key={v}>
127	            <Content component="p">{v}</Content>
128	          </AccordionExpandableContentBody>
129	        ))}
130	      </>
131	    );
132	  };
133	
134	  const configContent = () => {
135	    return (
136	      <Content className="summary-text-container">
137	        <Content component={ContentVariants.h3}>{`${t('Configuration')}`}</Content>
138	        <Content component="p" className="summary-config-item">{`${t('Sampling')}: ${config.sampling}`}</Content>
139	        {maxChunkAge && (
140	          <Content component="p" className="summary-config-item">{`${t('Max chunk age')}: ${formatDuration(
141	            maxChunkAge
142	          )}`}</Content>
143	        )}
144	      </Content>
145	    );
146	  };
147	
148	  const versionContent = () => {
149	    return (
150	      <Content className="summary-text-container">
151	        <Content component={ContentVariants.h3}>{`${t('Version')}`}</Content>
152	        <Content component="p" className="summary-config-item">{`${t('Number')}: ${config.buildVersion}`}</Content>
153	        <Content component="p" className="summary-config-item">{`${t('Date')}: ${config.buildDate}`}</Content>
154	      </Content>
155	    );
156	  };
157	
158	  const cardinalityContent = () => {
159	    const rateMetrics = metrics.rate.map(r => r.bytes || r.packets).or([]);
160	
161	    //regroup all k8s objects per type + namespace
162	    const namespaces: string[] = [];
163	    const typesCardinality: TypeCardinality[] = [];
164	    let addresses: string[] = [];
165	    let ports: number[] = [];
166	    let protocols: number[] = [];
167	
168	    if (flows && flows.length) {
169	      //list all types
170	      const types = Array.from(new Set(flows.flatMap(f => [f.labels.SrcK8S_Type, f.labels.DstK8S_Type])));
171	      types
172	        .filter((t: string | undefined) => t !== undefined)
173	        .forEach((type: string) => {
174	          const tc: TypeCardinality = { type, objects: [] };
175	
176	          const typeFilteredFlows = flows.filter(f => [f.labels.SrcK8S_Type, f.labels.DstK8S_Type].includes(type));
177	          //list all namespaces of this type
178	          const typeNamespaces = new Set(
179	            typeFilteredFlows.flatMap(f => [f.labels.SrcK8S_Namespace, f.labels.DstK8S_Namespace])
180	          );
181	          typeNamespaces.forEach(namespace => {
182	            const namespaceFilteredFlows = typeFilteredFlows.filter(f =>
183	              [f.labels.SrcK8S_Namespace, f.labels.DstK8S_Namespace].includes(namespace)
184	            );
185	
186	            const nsObject: K8SObjectCardinality = {
187	              namespace,
188	              names: []
189	            };
190	
191	            //add all names of this namespace of type
192	            namespaceFilteredFlows.forEach(record => {
193	              const srcName =
194	                record.labels.SrcK8S_Type === type && record.labels.SrcK8S_Namespace === namespace
195	                  ? record.fields.SrcK8S_Name
196	                  : undefined;
197	              if (srcName && !nsObject.names.includes(srcName)) {
198	                nsObject.names.push(srcName);
199	              }
200	              const dstName =
201	                record.labels.DstK8S_Type === type && record.labels.DstK8S_Namespace === namespace
202	                  ? record.fields.DstK8S_Name
203	                  : undefined;
204	              if (dstName && !nsObject.names.includes(dstName)) {
205	                nsObject.names.push(dstName);
206	              }
207	            });
208	
209	            if (!_.isEmpty(nsObject.names)) {
210	              tc.objects.push(nsObject);
211	            }
212	
213	            if (namespace && !namespaces.includes(namespace)) {
214	              namespaces.push(namespace);
215	            }
216	          });
217	          typesCardinality.push(tc);
218	        });
219	
220	      addresses = Array.from(
221	        new Set(flows.map(f => f.fields.SrcAddr || '').concat(flows.map(f => f.fields.DstAddr || '')))
222	      );
223	      ports = Array.from(
224	        new Set(
225	          flows
226	            .filter(f => f.fields.SrcPort)
227	            .map(f => f.fields.SrcPort)
228	            .concat(flows.filter(f => f.fields.DstPort).map(f => f.fields.DstPort)) as number[]
229	        )
230	      );
231	      protocols = Array.from(new Set(flows.map(f => f.fields.Proto || NaN)));
232	    } else if (rateMetrics) {
233	      function manageTypeCardinality(hostName?: string, namespace?: string, type?: string, name?: string) {
234	        if (namespace && !namespaces.includes(namespace)) {
235	          namespaces.push(namespace);
236	        }
237	
238	        if (type) {
239	          let tc = typesCardinality.find(t => t.type === type);
240	          if (!tc) {
241	            tc = { type: type, objects: [] };
242	            typesCardinality.push(tc);
243	          }
244	
245	          let object = tc.objects.find(o => o.namespace === namespace);
246	          if (!object) {
247	            object = { names: [], namespace: namespace };
248	            tc.objects.push(object);
249	          }
250	
251	          if (name && !object.names.includes(name)) {
252	            object.names.push(name);
253	          }
254	        }
255	
256	        if (hostName) {
257	          manageTypeCardinality('', '', 'Node', hostName);
258	        }
259	      }
260	
261	      rateMetrics.forEach(m => {
262	        manageTypeCardinality(m.source.host, m.source.namespace, m.source.resource?.type, m.source.resource?.name);
263	        manageTypeCardinality(
264	          m.destination.host,
265	          m.destination.namespace,
266	          m.destination.resource?.type,
267	          m.destination.resource?.name
268	        );
269	      });
270	
271	      addresses = Array.from(
272	        new Set(rateMetrics.map(m => m.source.addr).concat(rateMetrics.map(m => m.destination.addr)))
273	      ).filter(v => !_.isEmpty(v)) as string[];
274	    }
275	
276	    if (!_.isEmpty(namespaces)) {
277	      typesCardinality.push({
278	        type: 'Namespace',
279	        objects: [{ names: namespaces }]
280	      });
281	    }
282	
283	    return addresses.length || typesCardinality.length || ports.length || protocols.length ? (
284	      <Content className="summary-text-container">
285	        <Content component={ContentVariants.h3}>{`${t('Cardinality')} ${
286	          !_.isEmpty(rateMetrics) ? t('(top {{limit}} metrics)', { limit }) : ''
287	        }`}</Content>
288	        <Accordion id="cardinality-accordion">
289	          {addresses.length
290	            ? accordionItem(
291	                'addresses',
292	                t('{{n}} IP(s)', { n: addresses.length }),
293	                listCardinalityContent(addresses, compareIPs)
294	              )
295	            : undefined}
296	          {typesCardinality.length
297	            ? typesCardinality.map(tc =>
298	                accordionItem(
299	                  tc.type,
300	                  `${tc.objects.map(o => o.names.length).reduce((a, b) => a + b, 0)} ${tc.type}(s)`,
301	                  typeCardinalityContent(tc)
302	                )
303	              )
304	            : undefined}
305	          {ports.length
306	            ? accordionItem(
307	                'ports',
308	                t('{{n}} Port(s)', { n: ports.length }),
309	                listCardinalityContent(
310	                  //sort ports before format to keep number order
311	                  ports.sort((p1, p2) => comparePorts(p1, p2)).map(p => formatPort(p))
312	                )
313	              )
314	            : undefined}
315	          {protocols.length
316	            ? accordionItem(
317	                'protocols',
318	                t('{{n}} Protocol(s)', { n: protocols.length }),
319	                listCardinalityContent(
320	                  protocols.map(p => formatProtocol(p, t)),
321	                  compareStrings
322	                )
323	              )
324	            : undefined}
325	        </Accordion>
326	      </Content>
327	    ) : undefined;
328	  };
329	
330	  const dnsLatency = (filteredFlows: Record[]) => {
331	    const filteredDNSFlows = filteredFlows.filter(f => f.fields.DnsLatencyMs !== undefined);
332	
333	    const dnsLatency = filteredDNSFlows.length
334	      ? filteredDNSFlows.map(f => f.fields.DnsLatencyMs!).reduce((a, b) => a + b, 0) / filteredDNSFlows.length
335	      : NaN;
336	
337	    return (
338	      <Content component="p" className="summary-config-item">{`${t('DNS latency')}: ${
339	        isNaN(dnsLatency) ? t('n/a') : formatDurationAboveMillisecond(dnsLatency)
340	      }`}</Content>
341	    );
342	  };
343	
344	  const rttLatency = (filteredFlows: Record[]) => {
345	    const filteredRTTFlows = filteredFlows.filter(f => f.fields.TimeFlowRttNs !== undefined);
346	
347	    const rtt = filteredRTTFlows.length
348	      ? filteredRTTFlows.map(f => f.fields.TimeFlowRttNs!).reduce((a, b) => a + b, 0) / filteredRTTFlows.length
349	      : NaN;
350	
351	    return (
352	      <Content component="p" className="summary-config-item">{`${t('Flow RTT')}: ${
353	        isNaN(rtt) ? t('n/a') : formatDurationAboveNanosecond(rtt)
354	      }`}</Content>
355	    );
356	  };
357	
358	  const timeContent = () => {
359	    const filteredFlows = flows || [];
360	    const duration = filteredFlows.length
361	      ? filteredFlows
362	          .map(f => (f.fields.TimeFlowEndMs || 0) - (f.fields.TimeFlowStartMs || 0))
363	          .reduce((a, b) => a + b, 0) / filteredFlows.length
364	      : 0;
365	    const collectionLatency = filteredFlows.length
366	      ? filteredFlows
367	          .map(f => (f.fields.TimeReceived || 0) * 1000 - (f.fields.TimeFlowEndMs || 0))
368	          .reduce((a, b) => a + b, 0) / filteredFlows.length
369	      : 0;
370	
371	    return flows && flows.length ? (
372	      <Content className="summary-text-container">
373	        <Content component={ContentVariants.h3}>{`${t('Average time')}`}</Content>
374	        <Content component="p" className="summary-config-item">{`${t('Duration')}: ${formatDurationAboveMillisecond(
375	          duration
376	        )}`}</Content>
377	        {showRTTLatency ? rttLatency(filteredFlows) : <></>}
378	        <Content component="p" className="summary-config-item">{`${t(
379	          'Collection latency'
380	        )}: ${formatDurationAboveMillisecond(collectionLatency)}`}</Content>
381	        {showDNSLatency ? dnsLatency(filteredFlows) : <></>}
382	      </Content>
383	    ) : (
384	      <></>
385	    );
386	  };
387	
388	  return (
389	    <div className="scrollable-panel">
390	      <Content className="summary-text-container">
391	        {!_.isEmpty(flows) && stats?.limitReached && (
392	          <Content component={ContentVariants.p}>
393	            {t(
394	              // eslint-disable-next-line max-len
395	              'Flow per request limit reached, following metrics can be inaccurate. Narrow down your search or increase limit.'
396	            )}
397	          </Content>
398	        )}
399	        <Content component={ContentVariants.h3}>{`${t('Results')} ${
400	          _.isEmpty(flows) ? t('(top {{limit}} metrics)', { limit }) : ''
401	        }`}</Content>
402	        {_.isEmpty(flows) ? (
403	          <MetricsQuerySummaryContent
404	            className="summary-container-grouped"
405	            direction="column"
406	            metrics={metrics}
407	            numQueries={stats?.numQueries}
408	            dataSources={stats?.dataSources}
409	            lastRefresh={lastRefresh}
410	            lastDuration={lastDuration}
411	            warning={warning}
412	          />
413	        ) : (
414	          <FlowsQuerySummaryContent
415	            className="summary-container-grouped"
416	            direction="column"
417	            type={type}
418	            flows={flows!}
419	            numQueries={stats?.numQueries}
420	            limitReached={stats?.limitReached || false}
421	            range={range}
422	            lastRefresh={lastRefresh}
423	            lastDuration={lastDuration}
424	            warning={warning}
425	          />
426	        )}
427	      </Content>
428	
429	      {timeContent()}
430	
431	      {cardinalityContent()}
432	
433	      {configContent()}
434	
435	      {versionContent()}
436	    </div>
437	  );
438	};
